class Solution:
    def superpalindromesInRange(self, left, right):
        L, R = int(left), int(right)
        def is_pal(n):
            s = str(n)
            return s == s[::-1]
        count = 0
        # Enumerate palindromes up to 10^9 as roots
        # Odd length palindromes
        for half in range(1, 100001):
            s = str(half)
            pal = int(s + s[-2::-1])
            sq = pal * pal
            if sq > R:
                break
            if sq >= L and is_pal(sq):
                count += 1
        # Even length palindromes
        for half in range(1, 100001):
            s = str(half)
            pal = int(s + s[::-1])
            sq = pal * pal
            if sq > R:
                break
            if sq >= L and is_pal(sq):
                count += 1
        return count

