var superpalindromesInRange = function(left, right) {
    const L = BigInt(left), R = BigInt(right);
    function isPal(n) {
        const s = n.toString();
        return s === s.split('').reverse().join('');
    }
    let count = 0;
    // Odd-length palindromes
    for (let half = 1; half <= 100000; half++) {
        const s = half.toString();
        const pal = BigInt(s + s.slice(0, -1).split('').reverse().join(''));
        const sq = pal * pal;
        if (sq > R) break;
        if (sq >= L && isPal(sq)) count++;
    }
    // Even-length palindromes
    for (let half = 1; half <= 100000; half++) {
        const s = half.toString();
        const pal = BigInt(s + s.split('').reverse().join(''));
        const sq = pal * pal;
        if (sq > R) break;
        if (sq >= L && isPal(sq)) count++;
    }
    return count;
};
